const raw = $json;
const configs = Array.isArray(raw)
  ? raw
  : Array.isArray(raw.data)
    ? raw.data
    : raw && Object.keys(raw).length
      ? [raw]
      : [];

return configs.map((config) => ({ json: config }));

const crypto = require('crypto');

const config = $json;
const {
  brand_id,
  sync_type = 'csv',
  source_url,
  api_key,
  field_map = {},
} = config;

if (!brand_id || !source_url) {
  throw new Error('brand_id y source_url son requeridos');
}

// VALORES HARDCODADOS (configurados manualmente)
const apiBase = 'https://api.lookitry.com';
const enterpriseToken = $env.ENTERPRISE_SYNC_TOKEN;
const removeBgApiKey = $env.REMOVEBG_API_KEY;
const minioEndpoint = 'https://minio.wilkiedevs.com';
const minioBucket = 'images';
const minioAccessKey = $env.MINIO_ACCESS_KEY;
const minioSecretKey = $env.MINIO_SECRET_KEY;
const minioPublicUrl = 'https://minio.wilkiedevs.com';

function parseCsvLine(line) {
  const values = [];
  let current = '';
  let inQuotes = false;

  for (let i = 0; i < line.length; i += 1) {
    const char = line[i];
    const next = line[i + 1];

    if (char === '"') {
      if (inQuotes && next === '"') {
        current += '"';
        i += 1;
      } else {
        inQuotes = !inQuotes;
      }
      continue;
    }

    if (char === ',' && !inQuotes) {
      values.push(current.trim());
      current = '';
      continue;
    }

    current += char;
  }

  values.push(current.trim());
  return values;
}

function parseCsv(text) {
  const lines = text
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter(Boolean);

  if (lines.length < 2) return [];

  const headers = parseCsvLine(lines[0]);
  return lines.slice(1).map((line) => {
    const values = parseCsvLine(line);
    return headers.reduce((acc, header, index) => {
      acc[header] = values[index] ?? '';
      return acc;
    }, {});
  });
}

function extractCollection(data) {
  if (Array.isArray(data)) return data;
  if (Array.isArray(data.products)) return data.products;
  if (Array.isArray(data.items)) return data.items;
  if (Array.isArray(data.data)) return data.data;
  return [];
}

function pick(record, target, fallbacks = []) {
  const mappedKey = field_map[target];
  const keys = [mappedKey, target, ...fallbacks].filter(Boolean);

  for (const key of keys) {
    const value = record?.[key];
    if (value !== undefined && value !== null && String(value).trim() !== '') {
      return value;
    }
  }

  return null;
}

function buildCatalogHeaders(rawKey) {
  if (!rawKey) return {};
  if (typeof rawKey !== 'string') return {};
  if (rawKey.includes(':')) {
    const encoded = Buffer.from(rawKey).toString('base64');
    return { Authorization: `Basic ${encoded}` };
  }
  return { Authorization: `Bearer ${rawKey}` };
}

function sha256Hex(data) {
  return crypto.createHash('sha256').update(data).digest('hex');
}

function hmac(key, data, encoding) {
  return crypto.createHmac('sha256', key).update(data).digest(encoding);
}

function getSignatureKey(secretKey, dateStamp, region, service) {
  const kDate = hmac(`AWS4${secretKey}`, dateStamp);
  const kRegion = hmac(kDate, region);
  const kService = hmac(kRegion, service);
  return hmac(kService, 'aws4_request');
}

async function uploadToMinio(buffer, objectKey) {
  const endpointUrl = new URL(minioEndpoint);
  const host = endpointUrl.host;
  const pathname = `/${minioBucket}/${objectKey}`;
  const url = `${minioEndpoint}${pathname}`;
  const method = 'PUT';
  const service = 's3';
  const region = 'us-east-1';
  const now = new Date();
  const amzDate = now.toISOString().replace(/[:-]|\.\d{3}/g, '').slice(0, 15) + 'Z';
  const dateStamp = amzDate.slice(0, 8);
  const payloadHash = sha256Hex(buffer);
  const canonicalHeaders = `host:${host}\nx-amz-content-sha256:${payloadHash}\nx-amz-date:${amzDate}\n`;
  const signedHeaders = 'host;x-amz-content-sha256;x-amz-date';
  const canonicalRequest = [
    method,
    pathname,
    '',
    canonicalHeaders,
    signedHeaders,
    payloadHash,
  ].join('\n');
  const credentialScope = `${dateStamp}/${region}/${service}/aws4_request`;
  const stringToSign = [
    'AWS4-HMAC-SHA256',
    amzDate,
    credentialScope,
    sha256Hex(canonicalRequest),
  ].join('\n');
  const signingKey = getSignatureKey(minioSecretKey, dateStamp, region, service);
  const signature = crypto.createHmac('sha256', signingKey).update(stringToSign).digest('hex');
  const authorizationHeader = `AWS4-HMAC-SHA256 Credential=${minioAccessKey}/${credentialScope}, SignedHeaders=${signedHeaders}, Signature=${signature}`;

  const response = await fetch(url, {
    method,
    headers: {
      Host: host,
      'Content-Type': 'image/png',
      'Content-Length': String(buffer.length),
      'x-amz-content-sha256': payloadHash,
      'x-amz-date': amzDate,
      Authorization: authorizationHeader,
    },
    body: buffer,
  });

  if (!response.ok) {
    const detail = await response.text();
    throw new Error(`MinIO upload falló: ${response.status} ${detail}`);
  }
}

const catalogResponse = await fetch(source_url, {
  method: 'GET',
  headers: buildCatalogHeaders(api_key),
});

if (!catalogResponse.ok) {
  throw new Error(`No se pudo consultar el catálogo: ${catalogResponse.status} ${catalogResponse.statusText}`);
}

const rawBody = await catalogResponse.text();
let records = [];

if (sync_type === 'csv' || /(^|\n).+,.+(\n|$)/.test(rawBody)) {
  records = parseCsv(rawBody);
} else {
  const parsed = JSON.parse(rawBody);
  records = extractCollection(parsed);
}

const products = records
  .map((record) => ({
    brand_id,
    external_id: String(pick(record, 'external_id', ['id', 'sku', 'product_id']) || '').trim(),
    name: pick(record, 'name', ['title', 'product_name']),
    description: pick(record, 'description', ['body_html', 'details', 'short_description']),
    category: pick(record, 'category', ['type', 'product_type', 'collection']),
    image_url_original: pick(record, 'image_url', ['image', 'image_src', 'imageUrl', 'featured_image']),
    price: pick(record, 'price', ['regular_price', 'sale_price']),
  }))
  .filter((product) => product.name && product.image_url_original);

let successCount = 0;
let failedCount = 0;
const failures = [];

for (let index = 0; index < products.length; index += 1) {
  const product = products[index];

  try {
    const removalBody = new URLSearchParams({
      image_url: String(product.image_url_original),
      size: 'auto',
    });

    const removeBgResponse = await fetch('https://api.remove.bg/v1.0/removebg', {
      method: 'POST',
      headers: {
        'X-Api-Key': removeBgApiKey,
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: removalBody.toString(),
    });

    if (!removeBgResponse.ok) {
      const detail = await removeBgResponse.text();
      throw new Error(`remove.bg falló: ${removeBgResponse.status} ${detail}`);
    }

    const arrayBuffer = await removeBgResponse.arrayBuffer();
    const pngBuffer = Buffer.from(arrayBuffer);
    const safeExternalId = product.external_id || `generated-${index + 1}`;
    const objectKey = `enterprise/${brand_id}/${safeExternalId}.png`;

    await uploadToMinio(pngBuffer, objectKey);

    const finalImageUrl = `${minioPublicUrl}/${minioBucket}/${objectKey}`;
    const notifyResponse = await fetch(`${apiBase}/api/enterprise/sync-product`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${enterpriseToken}`,
      },
      body: JSON.stringify({
        brand_id,
        external_id: safeExternalId,
        name: product.name,
        description: product.description,
        category: product.category,
        image_url: finalImageUrl,
        price: product.price,
      }),
    });

    if (!notifyResponse.ok) {
      const detail = await notifyResponse.text();
      throw new Error(`Backend Lookitry falló: ${notifyResponse.status} ${detail}`);
    }

    successCount += 1;
  } catch (error) {
    failedCount += 1;
    failures.push(`${product.name}: ${error.message}`);
  }
}

const status = successCount > 0 && failedCount === 0
  ? 'success'
  : successCount > 0
    ? 'partial'
    : 'failed';

const message = failedCount > 0
  ? failures.slice(0, 3).join(' | ')
  : `Sync completado con ${successCount} productos.`;

return [{
  json: {
    brand_id,
    status,
    message,
    products_received: products.length,
    products_synced_count: successCount,
    failed_count: failedCount,
    failures,
  },
}];
